+#[allow(dead_code)]
+pub(crate) fn inspect_focused_target() -> Result<FocusedTargetSnapshot, FriendlyInsertRunError> {
+    let focused = unsafe { find_focused_accessible()? };
+    inspect_focused_target_from_accessible(&focused)
